{
  "core_hypothesis_preview": "Integrating direct in‑situ aerosol liquid water (ALW) measurements with heterogeneous uptake observations will reconcile model‑estimated multiphase chemistry with real atmospheric behavior.",
  "subtopics": [
    {
      "topic_name": "Model Representation Gaps for ALW and Heterogeneous Chemistry",
      "description": "Assess how current chemical‑transport and data‑assimilation models (e.g., MACC, STEAM2, GEOS‑Chem) treat aerosol liquid water and aerosol‑gas coupling, and identify the quantitative mismatches that motivate new observations.",
      "sub_questions": [
        "What assumptions do existing models make about ALW quantity and its partitioning among aerosol phases?",
        "How do those assumptions translate into systematic biases in simulated aerosol optical depth and trace‑gas uptake (e.g., N₂O₅, ClNO₂)?",
        "Which model components (emission scaling, water‑condensation schemes, aerosol‑gas interaction modules) are most responsible for the observed discrepancies?"
      ],
      "assigned_plan_ids": ["plan_0_0", "plan_1_1", "plan_1_2", "plan_3_7", "plan_3_8", "plan_3_9", "plan_4_10", "plan_4_11"],
      "keywords": ["model bias", "ALW parameterisation", "aerosol‑gas coupling", "MACC", "STEAM2"]
    },
    {
      "topic_name": "Aircraft‑Based In‑Situ ALW Measurements",
      "description": "Summarise the limited aircraft campaigns that have recorded aerosol liquid water or related proxies, evaluating their relevance to heterogeneous chemistry and highlighting data gaps.",
      "sub_questions": [
        "Which aircraft missions have reported any metric of aerosol liquid water (e.g., ALWC, hygroscopic growth) and what are their spatial/temporal coverages?",
        "Do any of those missions also provide simultaneous measurements of heterogeneous reactive gases (N₂O₅, ClNO₂, HNO₃) that enable direct linkage to ALW?",
        "What methodological limitations (instrument sensitivity, altitude range, sampling frequency) prevent these datasets from fully addressing the research need?"
      ],
      "assigned_plan_ids": ["plan_2_4", "plan_3_9", "plan_4_10", "plan_1_3"],
      "keywords": ["aircraft campaign", "ALWC", "CIMS", "NEAQS‑ITCT", "in‑situ"]
    },
    {
      "topic_name": "Ground‑Based and FT‑Based ALW/Hygroscopicity Observations",
      "description": "Explore surface and tower measurements—including HTDMA, CCN, and aerosol‑mass‑spectrometry—that quantify aerosol water content or hygroscopic growth, and assess their utility for linking to multiphase reactions.",
      "sub_questions": [
        "What ground‑based instruments (HTDMA, CCN counters, AMS) have produced quantitative ALW or growth‑factor time series?",
        "How have these hygroscopicity datasets been used to infer or validate heterogeneous uptake rates of N₂O₅ or ClNO₂ in the field?",
        "What gaps remain in temporal resolution, aerosol composition, or concurrent gas‑phase chemistry that limit direct coupling to heterogeneous processes?"
      ],
      "assigned_plan_ids": ["plan_2_5", "plan_3_7", "plan_4_11", "plan_2_6"],
      "keywords": ["HTDMA", "CCN", "ground station", "hygroscopic growth", "AMS"]
    },
    {
      "topic_name": "Laboratory Chamber Studies of ALW‑Controlled Heterogeneous Uptake",
      "description": "Identify controlled experiments that vary aerosol liquid water to measure uptake coefficients of N₂O₅ or ClNO₂, and evaluate how their findings can inform field measurement strategies.",
      "sub_questions": [
        "Which chamber experiments have systematically altered aerosol liquid water content and reported corresponding uptake coefficients for N₂O₅ or ClNO₂?",
        "What are the observed dependencies of uptake efficiency on relative humidity, aerosol composition, and liquid‑water fraction?",
        "How can the mechanistic insights from these laboratory studies be translated into observable signatures for aircraft or ground‑based campaigns?"
      ],
      "assigned_plan_ids": ["plan_2_6", "plan_3_8", "plan_2_6"],
      "keywords": ["chamber experiment", "uptake coefficient", "N₂O₅", "ClNO₂", "relative humidity"]
    }
  ]
}
